SELECT COUNT(DISTINCT followed_id) AS num_users_with_public_followers
FROM user_follows
WHERE visibility = 'public';

SELECT DISTINCT u.username
FROM users u
INNER JOIN user_follows uf ON u.user_id = uf.follower_id;

SELECT COUNT(DISTINCT follower_id) 
FROM user_follows 
WHERE visibility = 'public';

SELECT follower_id AS user_id 
FROM user_follows 
WHERE follower_id = followed_id;

SELECT DISTINCT user_id 
FROM interactions 
WHERE verb = 'is following' AND created_at LIKE '2018-10-22%';

SELECT user_id 
FROM content_likes 
WHERE content_id = 1 AND like_date = '2018-10-23 14:00:00';

SELECT COUNT(*) 
FROM user_follows 
WHERE followed_id = (SELECT user_id FROM users WHERE username = 'jane_smith');

SELECT user_id, COUNT(*) AS like_count
FROM content_likes
GROUP BY user_id;

SELECT content_id
FROM content_likes
WHERE user_id = 1;

SELECT MIN(like_date) AS oldest_like_date
FROM content_likes
WHERE user_id = 1;
